/**
 * Quantitative demonstration: does the gate actually earn its keep, and
 * does registry learning actually help, measured -- not narrated -- on a
 * large simulated corpus using the real production code paths (execute(),
 * deriveConfidenceVector(), classify(), the registry), not a reimplemented
 * toy model.
 *
 * Honesty constraints on the simulation, spelled out because a benchmark
 * that grades its own homework is worthless:
 *
 * 1. Ground truth ("would this attempt actually have succeeded?") is
 *    generated by a DIFFERENT formula than confidence.ts's own
 *    deriveConfidenceVector/computeConfidence (a noisy-OR combination of
 *    saturating risk terms, vs. confidence.ts's weighted linear sum). The
 *    classifier under test never sees this function -- it only sees the
 *    same DomState any other caller would.
 * 2. Every trial's "nature" outcome (would-this-attempt-succeed) is drawn
 *    ONCE per trial and reused across both the baseline and ERAL strategy,
 *    so differences in measured failure rate reflect the *decision*, not
 *    resampling noise.
 * 3. One archetype (`noisy_but_reliable`) is deliberately constructed so
 *    the stateless heuristic is systematically wrong (chronically
 *    borderline DOM signal, but genuinely high true reliability) -- this
 *    is the case Pillar 1 (registry) exists for, and the benchmark reports
 *    it separately rather than averaging it away.
 */

import {
  DomState,
  Task,
  classify,
  computeConfidence,
  deriveConfidenceVector,
  execute,
  InMemoryRegistryStore,
} from "../src/index.js";

// ---------- Seeded RNG (mulberry32) so this report is reproducible ----------
function mulberry32(seed: number) {
  let a = seed;
  return () => {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
const rng = mulberry32(20260706);
const uniform = (lo: number, hi: number) => lo + rng() * (hi - lo);
const chance = (p: number) => rng() < p;

// ---------- World model: DOM sampling + ground truth, per site archetype ----------
interface Archetype {
  name: string;
  sampleDom: () => DomState;
  /** Success probability floor when the world-risk signal is maxed out (0 = genuinely fragile, ~1 = the DOM signal is a red herring). */
  floorReliability: number;
  /** Success probability when the world-risk signal is ~0. */
  baseReliability: number;
}

/**
 * Combines the same three underlying signals confidence.ts measures
 * (DOM stability, interrupt/readiness, network calm) via a noisy-OR
 * (multiplicative independence) instead of confidence.ts's weighted
 * linear sum -- a genuinely different combination rule, not just relabeled
 * weights, so the classifier under test is not graded against its own
 * formula. Per-factor risk uses the same scale confidence.ts uses (so
 * archetypes designed to be predictable from the DOM signal actually are);
 * the *combination rule* differs, and one archetype (`noisy_but_reliable`)
 * is deliberately parameterized so its true reliability stays high even at
 * this world's moderate risk levels.
 */
function worldRisk(dom: DomState): number {
  const domRisk = clamp01(dom.mutationCount / 20) * 0.6 + clamp01(dom.layoutShiftScore) * 0.4;
  const networkRisk =
    dom.pendingNetworkRequests > 0 ? 1 - clamp01(dom.msSinceNetworkIdle / 3000) : 1 - clamp01(dom.msSinceNetworkIdle / 1000);
  const interruptRisk = dom.interruptPresent || !dom.targetElementReady ? 1 : 0;
  return 1 - (1 - domRisk) * (1 - networkRisk) * (1 - interruptRisk);
}

function clamp01(n: number): number {
  return Math.min(1, Math.max(0, n));
}

function trueSuccessProb(dom: DomState, arch: Archetype): number {
  const risk = worldRisk(dom);
  const p = arch.baseReliability * (1 - risk) + arch.floorReliability * risk;
  const noise = uniform(-0.03, 0.03);
  return Math.min(1, Math.max(0, p + noise));
}

const ARCHETYPES: Archetype[] = [
  {
    name: "stable_spa",
    baseReliability: 0.985,
    floorReliability: 0.4,
    sampleDom: () => ({
      observedAt: Date.now(),
      mutationCount: Math.round(uniform(0, 3)),
      layoutShiftScore: uniform(0, 0.05),
      pendingNetworkRequests: chance(0.1) ? 1 : 0,
      msSinceNetworkIdle: uniform(800, 2000),
      interruptPresent: chance(0.03),
      targetElementReady: chance(0.97),
    }),
  },
  {
    name: "flaky_widget",
    baseReliability: 0.95,
    floorReliability: 0.15,
    sampleDom: () => ({
      observedAt: Date.now(),
      mutationCount: Math.round(uniform(0, 20)),
      layoutShiftScore: uniform(0, 0.6),
      pendingNetworkRequests: chance(0.5) ? Math.round(uniform(1, 3)) : 0,
      msSinceNetworkIdle: uniform(50, 2500),
      interruptPresent: chance(0.15),
      targetElementReady: chance(0.85),
    }),
  },
  {
    // Modeled on the Ghost "Publish" atom: autosave PATCH never quite looks
    // settled, so the raw DOM signal is chronically borderline even though
    // the action is, in truth, highly reliable. See examples/registry-learning-demo.ts.
    name: "noisy_but_reliable",
    baseReliability: 0.95,
    floorReliability: 0.9,
    sampleDom: () => ({
      observedAt: Date.now(),
      mutationCount: Math.round(uniform(2, 6)),
      layoutShiftScore: uniform(0.05, 0.15),
      pendingNetworkRequests: chance(0.8) ? 1 : 0,
      msSinceNetworkIdle: uniform(200, 500),
      interruptPresent: chance(0.02),
      targetElementReady: chance(0.96),
    }),
  },
  {
    name: "adversarial_popup",
    baseReliability: 0.97,
    floorReliability: 0.05,
    sampleDom: () => {
      const interrupted = chance(0.4);
      return {
        observedAt: Date.now(),
        mutationCount: Math.round(uniform(0, 5)),
        layoutShiftScore: uniform(0, 0.1),
        pendingNetworkRequests: chance(0.1) ? 1 : 0,
        msSinceNetworkIdle: uniform(500, 1500),
        interruptPresent: interrupted,
        targetElementReady: interrupted ? chance(0.2) : chance(0.95),
      };
    },
  },
];

const TASK: Task = { id: "bench", description: "benchmark atom", targetSelector: "#el", kind: "click" };

// ---------- Experiment 1: does the stateless gate earn its keep? ----------
interface Trial {
  archetype: string;
  dom: DomState;
  trueP: number;
  wouldSucceed: boolean;
}

function generateTrials(n: number): Trial[] {
  const trials: Trial[] = [];
  for (let i = 0; i < n; i++) {
    const arch = ARCHETYPES[i % ARCHETYPES.length];
    const dom = arch.sampleDom();
    const trueP = trueSuccessProb(dom, arch);
    const wouldSucceed = chance(trueP);
    trials.push({ archetype: arch.name, dom, trueP, wouldSucceed });
  }
  return trials;
}

interface Tally {
  attempted: number;
  failed: number;
  deferred: number;
  deferredWouldHaveSucceeded: number;
  deferredWouldHaveFailed: number;
}

function emptyTally(): Tally {
  return { attempted: 0, failed: 0, deferred: 0, deferredWouldHaveSucceeded: 0, deferredWouldHaveFailed: 0 };
}

async function runExperiment1(trials: Trial[]) {
  const baseline = emptyTally();
  const eral = emptyTally();

  for (let i = 0; i < trials.length; i++) {
    const trial = trials[i];
    // Baseline: naive try-catch automation, always attempts.
    baseline.attempted += 1;
    if (!trial.wouldSucceed) baseline.failed += 1;

    // ERAL v1 stateless gate: no registry, no simulation, no human in the
    // loop -- confirm/fallback both decline, isolating the SAFE gate's own
    // precision. Real execute() call, real production classify() path.
    const outcome = await execute({ ...TASK, id: `${TASK.id}-${i}` }, trial.dom, {
      runAction: () => trial.wouldSucceed,
      confirm: () => false,
      fallback: () => false,
    });

    if (outcome.riskClass === "SAFE") {
      eral.attempted += 1;
      if (!trial.wouldSucceed) eral.failed += 1;
    } else {
      eral.deferred += 1;
      if (trial.wouldSucceed) eral.deferredWouldHaveSucceeded += 1;
      else eral.deferredWouldHaveFailed += 1;
    }
  }

  return { baseline, eral };
}

// ---------- Experiment 2: does registry learning recover the miscalibrated archetype? ----------
async function runExperiment2(rounds: number, trajectoryCount: number) {
  const noisyArch = ARCHETYPES.find((a) => a.name === "noisy_but_reliable")!;
  const registry = new InMemoryRegistryStore("bench-source");
  const domain = "noisy-but-reliable.example.com";

  const perRound: { round: number; autonomousSafeRate: number; failureRateAmongExecuted: number }[] = [];

  for (let round = 1; round <= rounds; round++) {
    let autonomousSafe = 0;
    let executed = 0;
    let failed = 0;
    for (let t = 0; t < trajectoryCount; t++) {
      const dom = noisyArch.sampleDom();
      const wouldSucceed = chance(trueSuccessProb(dom, noisyArch));
      // task.id includes the round: execute() is idempotent per task.id
      // (by design -- it never repeats a settled real-world action), so a
      // fresh id per round is required to get a fresh real invocation each
      // time, exactly as a new day's cron run would have a new task.id.
      const task: Task = { id: `noisy-${t}-round-${round}`, description: "noisy atom", targetSelector: `#el-${t}`, kind: "click" };

      const outcome = await execute(task, dom, {
        registry,
        domain,
        runAction: () => wouldSucceed,
        // A human bootstraps uncertain rounds early on -- exactly the
        // registry-learning-demo.ts pattern -- so the registry has real
        // evidence to learn from. What we measure is how much LESS this
        // human is needed as rounds pass, via outcome.riskClass, not
        // whether an attempt happened at all (that's always true here
        // since confirm always approves -- the point is autonomy).
        confirm: () => true,
        fallback: () => false,
      });

      if (outcome.riskClass === "SAFE") autonomousSafe += 1;

      if (outcome.finalState === "SETTLED" || outcome.finalState === "ABORTED") {
        // A real attempt was made (SAFE execution, or confirmed UNCERTAIN).
        executed += 1;
        if (!outcome.success) failed += 1;
      }
    }
    perRound.push({
      round,
      autonomousSafeRate: autonomousSafe / trajectoryCount,
      failureRateAmongExecuted: executed > 0 ? failed / executed : 0,
    });
  }

  return perRound;
}

// ---------- Experiment 3: classifier discrimination (precision/recall vs. ground-truth reliability) ----------
const RELIABLE_THRESHOLD = 0.85;

function runExperiment3(trials: Trial[]) {
  let truePositive = 0; // classified SAFE, genuinely reliable (trueP >= threshold)
  let falsePositive = 0; // classified SAFE, genuinely NOT reliable -- the dangerous case
  let falseNegative = 0; // NOT classified SAFE, genuinely reliable -- opportunity cost
  let trueNegative = 0; // NOT classified SAFE, genuinely NOT reliable -- correctly cautious

  for (const trial of trials) {
    const vector = deriveConfidenceVector(trial.dom);
    const confidence = computeConfidence(vector);
    const predictedSafe = classify(confidence) === "SAFE";
    const genuinelyReliable = trial.trueP >= RELIABLE_THRESHOLD;

    if (predictedSafe && genuinelyReliable) truePositive += 1;
    else if (predictedSafe && !genuinelyReliable) falsePositive += 1;
    else if (!predictedSafe && genuinelyReliable) falseNegative += 1;
    else trueNegative += 1;
  }

  return {
    truePositive,
    falsePositive,
    falseNegative,
    trueNegative,
    precision: truePositive / (truePositive + falsePositive),
    recall: truePositive / (truePositive + falseNegative),
  };
}

// ---------- Report ----------
function pct(n: number): string {
  return `${(n * 100).toFixed(2)}%`;
}

async function main() {
  console.log("=".repeat(78));
  console.log("EXPERIMENT 1 — stateless gate vs. naive try-catch, N=20000 mixed trials");
  console.log("=".repeat(78));

  const trials = generateTrials(20000);
  const { baseline, eral } = await runExperiment1(trials);

  console.log(`\nBaseline (always attempt, no gate):`);
  console.log(`  attempted: ${baseline.attempted}, failed: ${baseline.failed}, failure rate: ${pct(baseline.failed / baseline.attempted)}`);

  console.log(`\nERAL v1 (stateless SAFE gate, no registry, no human, no fallback):`);
  console.log(`  executed:  ${eral.attempted}, failed: ${eral.failed}, failure rate among executed: ${pct(eral.failed / eral.attempted)}`);
  console.log(`  deferred:  ${eral.deferred} (${pct(eral.deferred / trials.length)} of all trials)`);
  console.log(`    of which would have SUCCEEDED anyway (opportunity cost): ${eral.deferredWouldHaveSucceeded} (${pct(eral.deferredWouldHaveSucceeded / eral.deferred)})`);
  console.log(`    of which would have FAILED (correctly avoided):          ${eral.deferredWouldHaveFailed} (${pct(eral.deferredWouldHaveFailed / eral.deferred)})`);

  const failuresAvoided = eral.deferredWouldHaveFailed;
  const totalWouldFail = baseline.failed;
  console.log(`\n  Failures ERAL avoided vs. baseline: ${failuresAvoided} of ${totalWouldFail} total real failures in the corpus (${pct(failuresAvoided / totalWouldFail)} caught before they happened)`);
  console.log(`  Relative reduction in per-attempt failure rate: ${pct(1 - (eral.failed / eral.attempted) / (baseline.failed / baseline.attempted))}`);

  console.log(`\n${"=".repeat(78)}`);
  console.log(`EXPERIMENT 3 — classifier discrimination (ground truth: reliable if trueP >= ${RELIABLE_THRESHOLD})`);
  console.log("=".repeat(78));

  const exp3 = runExperiment3(trials);
  console.log(`\nConfusion matrix over the same ${trials.length} trials:`);
  console.log(`  true positive  (SAFE, genuinely reliable):     ${exp3.truePositive}`);
  console.log(`  false positive (SAFE, genuinely UNRELIABLE):   ${exp3.falsePositive}  <- the dangerous case`);
  console.log(`  false negative (not SAFE, genuinely reliable): ${exp3.falseNegative}  <- opportunity cost`);
  console.log(`  true negative  (not SAFE, genuinely unreliable): ${exp3.trueNegative}`);
  console.log(`\n  Precision (of everything auto-executed, how much was truly reliable): ${pct(exp3.precision)}`);
  console.log(`  Recall (of everything truly reliable, how much did we auto-execute):   ${pct(exp3.recall)}`);

  console.log(`\n${"=".repeat(78)}`);
  console.log("EXPERIMENT 2 — registry learning on the chronically-misjudged archetype");
  console.log(`(noisy_but_reliable: DOM signal always looks borderline, true reliability ~95%)`);
  console.log("=".repeat(78));

  const rounds = await runExperiment2(30, 20);
  const first = rounds[0];
  const last = rounds[rounds.length - 1];

  console.log(`\nRound 1  (no history yet):     ${pct(first.autonomousSafeRate)} of trajectories auto-executed with NO human confirmation, failure rate among all executed (auto + human-confirmed): ${pct(first.failureRateAmongExecuted)}`);
  console.log(`Round ${last.round} (learned history): ${pct(last.autonomousSafeRate)} of trajectories auto-executed with NO human confirmation, failure rate among all executed (auto + human-confirmed): ${pct(last.failureRateAmongExecuted)}`);
  console.log(`\n(A human still approves every non-SAFE case in this simulation, so every real attempt is checked either way -- the registry changes how OFTEN a human has to be the one to check, not whether failures get caught.)`);

  console.log(`\nAutonomous SAFE-execution rate by round (every 5th round):`);
  for (const r of rounds) {
    if (r.round === 1 || r.round % 5 === 0) {
      console.log(`  round ${String(r.round).padStart(2)}: ${pct(r.autonomousSafeRate)} autonomous, failure rate among executed: ${pct(r.failureRateAmongExecuted)}`);
    }
  }
}

main();
